"use client";

import * as React from "react";
import { ArrowLeft, ArrowRight } from "lucide-react";
import {
  motion,
  type MotionValue,
  useMotionValue,
  useMotionValueEvent,
  useReducedMotion,
  useSpring,
  useTransform,
} from "motion/react";

import {
  DepthCameraScene,
  type DepthCameraLayer,
  type DepthCameraSceneProps,
} from "@/components/experience/depth-camera-scene";
import { HorizontalTrack } from "@/components/experience/horizontal-track";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export type CinematicWorldCatalog = {
  heading: React.ReactNode;
  items: React.ReactNode[];
  label: string;
  eyebrow?: React.ReactNode;
  itemClassName?: string | ((index: number) => string | undefined);
  trackClassName?: string;
};

export type CinematicWorldSceneProps = Omit<
  DepthCameraSceneProps,
  "backOverlay" | "frontOverlay"
> & {
  catalog: CinematicWorldCatalog;
  chrome?: React.ReactNode;
  intro: React.ReactNode;
  rearNarrative?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  frontNarrative?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  layers: DepthCameraLayer[];
};

function resolveNarrative(
  narrative: CinematicWorldSceneProps["rearNarrative"] | CinematicWorldSceneProps["frontNarrative"],
  progress: MotionValue<number>,
) {
  return typeof narrative === "function" ? narrative(progress) : narrative;
}

function CinematicBackOverlay({
  intro,
  narrative,
  progress,
}: {
  intro: React.ReactNode;
  narrative?: CinematicWorldSceneProps["rearNarrative"];
  progress: MotionValue<number>;
}) {
  const introOpacity = useTransform(progress, [0, 0.08, 0.19, 0.27], [1, 1, 0.45, 0]);
  const introY = useTransform(progress, [0, 0.27], [0, -110]);
  const narrativeOpacity = useTransform(progress, [0.18, 0.28, 0.42, 0.52], [0, 1, 1, 0]);
  const narrativeY = useTransform(progress, [0.18, 0.33, 0.52], [140, 0, -150]);
  const narrativeScale = useTransform(progress, [0.18, 0.4, 0.52], [0.9, 1.06, 1.18]);
  return (
    <>
      <motion.div className="absolute inset-0" style={{ opacity: introOpacity, y: introY }}>
        {intro}
      </motion.div>
      {narrative ? (
        <motion.div
          className="absolute inset-0"
          style={{ opacity: narrativeOpacity, y: narrativeY, scale: narrativeScale }}
        >
          {resolveNarrative(narrative, progress)}
        </motion.div>
      ) : null}
    </>
  );
}

function CinematicFrontOverlay({
  catalog,
  chrome,
  narrative,
  progress,
}: {
  catalog: CinematicWorldCatalog;
  chrome?: React.ReactNode;
  narrative?: CinematicWorldSceneProps["frontNarrative"];
  progress: MotionValue<number>;
}) {
  const target = useMotionValue(0);
  const spring = useSpring(target, { stiffness: 160, damping: 32, mass: 0.28 });
  const reducedMotion = useReducedMotion();
  const trackProgress = reducedMotion ? target : spring;
  const [activeIndex, setActiveIndex] = React.useState(0);
  const [catalogInteractive, setCatalogInteractive] = React.useState(false);
  const chromeOpacity = useTransform(progress, [0.52, 0.66], [1, 0]);
  const narrativeOpacity = useTransform(progress, [0.43, 0.54, 0.67, 0.76], [0, 1, 1, 0]);
  const narrativeY = useTransform(progress, [0.43, 0.58, 0.76], [90, 0, -110]);
  const catalogOpacity = useTransform(progress, [0.74, 0.84, 0.92], [0, 0.76, 1]);
  const catalogY = useTransform(progress, [0.74, 0.92], ["18vh", "0vh"]);
  const catalogScale = useTransform(progress, [0.74, 0.92], [0.94, 1]);
  const scrimOpacity = useTransform(progress, [0.7, 0.91], [0, 0.84]);

  useMotionValueEvent(progress, "change", (value) => {
    const interactive = value >= 0.9;
    setCatalogInteractive((current) => current === interactive ? current : interactive);
    if (value < 0.72 && target.get() !== 0) {
      target.set(0);
      setActiveIndex(0);
    }
  });

  const goTo = (nextIndex: number) => {
    const lastIndex = Math.max(0, catalog.items.length - 1);
    const resolved = Math.max(0, Math.min(lastIndex, nextIndex));
    setActiveIndex(resolved);
    target.set(lastIndex === 0 ? 0 : resolved / lastIndex);
  };

  return (
    <>
      {chrome ? (
        <motion.div aria-hidden className="absolute inset-x-0 top-0 z-20" style={{ opacity: chromeOpacity }}>
          {chrome}
        </motion.div>
      ) : null}
      {narrative ? (
        <motion.div className="absolute inset-0 z-10" style={{ opacity: narrativeOpacity, y: narrativeY }}>
          {resolveNarrative(narrative, progress)}
        </motion.div>
      ) : null}
      <motion.div
        aria-hidden
        className="absolute inset-0 z-20 bg-[linear-gradient(180deg,rgba(5,9,12,.18),rgba(5,9,12,.94))]"
        style={{ opacity: scrimOpacity }}
      />
      <motion.div
        aria-hidden={!catalogInteractive}
        data-cinematic-catalog
        className={cn(
          "absolute inset-0 z-30 flex flex-col overflow-hidden pb-6 pt-24 text-white",
          catalogInteractive ? "pointer-events-auto" : "pointer-events-none",
        )}
        style={{ opacity: catalogOpacity, y: catalogY, scale: catalogScale }}
      >
        <div className="flex items-end justify-between gap-6 px-5 sm:px-[5vw]">
          <div>
            {catalog.eyebrow ? (
              <div className="text-[0.68rem] font-semibold uppercase tracking-[0.22em] text-white/52">
                {catalog.eyebrow}
              </div>
            ) : null}
            <div className="mt-3 text-[clamp(2.7rem,6vw,5.8rem)] font-semibold leading-[0.86] tracking-[-0.065em]">
              {catalog.heading}
            </div>
          </div>
          <div className="flex shrink-0 gap-2">
            <Button type="button" variant="outline" size="icon" className="rounded-full border-white/20 bg-black/15 text-white backdrop-blur-md hover:bg-white hover:text-black" aria-label="Cadrul anterior" disabled={!catalogInteractive || activeIndex === 0} onClick={() => goTo(activeIndex - 1)}>
              <ArrowLeft aria-hidden />
            </Button>
            <Button type="button" variant="outline" size="icon" className="rounded-full border-white/20 bg-black/15 text-white backdrop-blur-md hover:bg-white hover:text-black" aria-label="Cadrul următor" disabled={!catalogInteractive || catalog.items.length <= 1 || activeIndex === catalog.items.length - 1} onClick={() => goTo(activeIndex + 1)}>
              <ArrowRight aria-hidden />
            </Button>
          </div>
        </div>
        <div className="mt-6 min-h-0 flex-1">
          <HorizontalTrack label={catalog.label} progress={trackProgress} itemClassName={catalog.itemClassName} trackClassName={catalog.trackClassName} progressClassName="text-white">
            {catalog.items}
          </HorizontalTrack>
        </div>
      </motion.div>
    </>
  );
}

/** A composed Advanced recipe. Use `DepthCameraScene` directly for custom timelines. */
export function CinematicWorldScene({
  catalog,
  chrome,
  frontNarrative,
  intro,
  rearNarrative,
  ...props
}: CinematicWorldSceneProps) {
  return (
    <DepthCameraScene
      {...props}
      backOverlay={(progress) => (
        <CinematicBackOverlay intro={intro} narrative={rearNarrative} progress={progress} />
      )}
      frontOverlay={(progress) => (
        <CinematicFrontOverlay catalog={catalog} chrome={chrome} narrative={frontNarrative} progress={progress} />
      )}
    />
  );
}

"use client";

import * as React from "react";
import { type MotionValue, useMotionValue, useReducedMotion } from "motion/react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import {
  damp,
  mix,
  resolveKeyframes,
  supportsWebGL,
  useHydrated,
  useMediaQuery,
} from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";

export type DepthCameraLayerKeyframe = {
  at: number;
  x?: number;
  y?: number;
  z?: number;
  scale?: number;
  opacity?: number;
};

export type DepthCameraLayer = {
  id: string;
  src: string;
  mobileSrc?: string;
  plane: "back" | "front";
  depth: number;
  opacity?: number;
  timeline?: DepthCameraLayerKeyframe[];
};

export type DepthCameraBeat = {
  at: number;
  x?: number;
  y?: number;
  z: number;
  lookX?: number;
  lookY?: number;
  fov?: number;
};

export type DepthCameraSceneProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  layers: DepthCameraLayer[];
  poster: string;
  mobilePoster?: string;
  camera?: DepthCameraBeat[];
  scrollScreens?: number;
  smoothing?: number;
  maxDpr?: number;
  pointerStrength?: number;
  progress?: MotionValue<number>;
  backOverlay?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  frontOverlay?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  reducedMotionFallback?: React.ReactNode;
  stageClassName?: string;
  onProgressChange?: (progress: number) => void;
  mobileBreakpoint?: number;
};

type PlaneRecord = {
  layer: DepthCameraLayer;
  mesh: THREE.Mesh<THREE.PlaneGeometry, THREE.MeshBasicMaterial>;
  textureAspect: number;
};

const DEFAULT_CAMERA: DepthCameraBeat[] = [
  { at: 0, x: 0, y: 0, z: 9, lookX: 0, lookY: 0, fov: 46 },
  { at: 0.18, x: 0, y: 0, z: 8.1, lookX: 0, lookY: 0, fov: 45 },
  { at: 0.43, x: 0.08, y: 0.03, z: 6.25, lookX: 0.02, lookY: 0, fov: 43 },
  { at: 0.68, x: 0.26, y: 0.08, z: 4.35, lookX: 0.1, lookY: 0.01, fov: 41 },
  { at: 0.88, x: 0.58, y: 0.12, z: 3.15, lookX: 0.26, lookY: 0.02, fov: 39 },
  { at: 1, x: 0.72, y: 0.15, z: 2.72, lookX: 0.34, lookY: 0.02, fov: 38 },
];

function resolveNumber(value: number | undefined, fallback: number) {
  return value ?? fallback;
}

function sampleCamera(frames: DepthCameraBeat[], progress: number) {
  const { from, to, mix: amount } = resolveKeyframes(frames, progress);
  return {
    x: mix(resolveNumber(from.x, 0), resolveNumber(to.x, 0), amount),
    y: mix(resolveNumber(from.y, 0), resolveNumber(to.y, 0), amount),
    z: mix(from.z, to.z, amount),
    lookX: mix(resolveNumber(from.lookX, 0), resolveNumber(to.lookX, 0), amount),
    lookY: mix(resolveNumber(from.lookY, 0), resolveNumber(to.lookY, 0), amount),
    fov: mix(resolveNumber(from.fov, 46), resolveNumber(to.fov, 46), amount),
  };
}

function sampleLayer(layer: DepthCameraLayer, progress: number) {
  const frames = layer.timeline?.length
    ? layer.timeline
    : [{ at: 0 }, { at: 1 }];
  const { from, to, mix: amount } = resolveKeyframes(frames, progress);
  return {
    x: mix(resolveNumber(from.x, 0), resolveNumber(to.x, 0), amount),
    y: mix(resolveNumber(from.y, 0), resolveNumber(to.y, 0), amount),
    z: mix(resolveNumber(from.z, 0), resolveNumber(to.z, 0), amount),
    scale: mix(resolveNumber(from.scale, 1), resolveNumber(to.scale, 1), amount),
    opacity: mix(
      resolveNumber(from.opacity, layer.opacity ?? 1),
      resolveNumber(to.opacity, layer.opacity ?? 1),
      amount,
    ),
  };
}

function renderOverlay(
  overlay: DepthCameraSceneProps["backOverlay"] | DepthCameraSceneProps["frontOverlay"],
  progress: MotionValue<number>,
) {
  return typeof overlay === "function" ? overlay(progress) : overlay;
}

/**
 * A real-camera 2.5D engine for registered, full-canvas raster plates.
 * Back and front WebGL passes sandwich semantic DOM, so copy can be truly
 * occluded by the hero/foreground instead of faking depth with z-index alone.
 */
export function DepthCameraScene({
  backOverlay,
  camera = DEFAULT_CAMERA,
  className,
  frontOverlay,
  label,
  layers,
  maxDpr = 1.75,
  mobileBreakpoint = 768,
  mobilePoster,
  onPointerLeave,
  onPointerMove,
  onProgressChange,
  pointerStrength = 0.11,
  poster,
  progress: controlledProgress,
  reducedMotionFallback,
  scrollScreens = 6,
  smoothing = 10,
  stageClassName,
  style,
  ...props
}: DepthCameraSceneProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const stageRef = React.useRef<HTMLDivElement>(null);
  const backCanvasRef = React.useRef<HTMLCanvasElement>(null);
  const frontCanvasRef = React.useRef<HTMLCanvasElement>(null);
  const pointerRef = React.useRef({ x: 0, y: 0 });
  const targetPointerRef = React.useRef({ x: 0, y: 0 });
  const intersectionRef = React.useRef(true);
  const rawProgress = useElementScrollProgress(rootRef);
  const visibleProgress = useMotionValue(0);
  const reducedMotion = useReducedMotion();
  const hydrated = useHydrated();
  const mobile = useMediaQuery(`(max-width: ${mobileBreakpoint - 0.02}px)`);
  const sceneProgress = controlledProgress ?? rawProgress;
  const [ready, setReady] = React.useState(false);
  const [failed, setFailed] = React.useState(false);
  const prefersReducedMotion = hydrated && Boolean(reducedMotion);
  const layerSignature = React.useMemo(
    () => layers.map((layer) => `${layer.id}:${layer.src}:${layer.mobileSrc ?? ""}`).join("|"),
    [layers],
  );

  React.useEffect(() => {
    const stage = stageRef.current;
    const backCanvas = backCanvasRef.current;
    const frontCanvas = frontCanvasRef.current;
    if (!stage || !backCanvas || !frontCanvas || prefersReducedMotion) return;
    if (!supportsWebGL()) {
      const fallbackTimer = window.setTimeout(() => setFailed(true), 0);
      return () => window.clearTimeout(fallbackTimer);
    }

    let disposed = false;
    let frame = 0;
    let previousTime = performance.now();
    let smoothed = sceneProgress.get();
    const records: PlaneRecord[] = [];
    const backScene = new THREE.Scene();
    const frontScene = new THREE.Scene();
    const firstCamera = sampleCamera(camera, 0);
    const backCamera = new THREE.PerspectiveCamera(firstCamera.fov, 1, 0.05, 100);
    const frontCamera = new THREE.PerspectiveCamera(firstCamera.fov, 1, 0.05, 100);
    const lowPower = (navigator.hardwareConcurrency ?? 8) <= 4;
    const pixelRatio = Math.min(window.devicePixelRatio || 1, lowPower ? 1.25 : maxDpr);
    const rendererOptions: THREE.WebGLRendererParameters = {
      alpha: true,
      antialias: !lowPower,
      powerPreference: "high-performance",
      premultipliedAlpha: true,
    };
    const backRenderer = new THREE.WebGLRenderer({ ...rendererOptions, canvas: backCanvas });
    const frontRenderer = new THREE.WebGLRenderer({ ...rendererOptions, canvas: frontCanvas });
    for (const renderer of [backRenderer, frontRenderer]) {
      renderer.setPixelRatio(pixelRatio);
      renderer.outputColorSpace = THREE.SRGBColorSpace;
      renderer.toneMapping = THREE.NoToneMapping;
      renderer.setClearColor(0x000000, 0);
    }

    const abort = (event: Event) => {
      event.preventDefault();
      if (!disposed) setFailed(true);
    };
    backCanvas.addEventListener("webglcontextlost", abort);
    frontCanvas.addEventListener("webglcontextlost", abort);

    const manager = new THREE.LoadingManager();
    const loader = new THREE.TextureLoader(manager);
    const activeLayers = lowPower
      ? layers.filter((layer) => layer.id !== "50-edge-frame")
      : layers;

    const load = async () => {
      const loaded = await Promise.all(activeLayers.map(async (layer, index) => {
        const source = mobile && layer.mobileSrc ? layer.mobileSrc : layer.src;
        const texture = await loader.loadAsync(source);
        texture.colorSpace = THREE.SRGBColorSpace;
        texture.anisotropy = Math.min(8, backRenderer.capabilities.getMaxAnisotropy());
        texture.generateMipmaps = true;
        texture.minFilter = THREE.LinearMipmapLinearFilter;
        texture.magFilter = THREE.LinearFilter;
        const image = texture.image as HTMLImageElement;
        const textureAspect = Math.max(0.01, image.naturalWidth / Math.max(1, image.naturalHeight));
        const geometry = new THREE.PlaneGeometry(textureAspect, 1, 1, 1);
        const material = new THREE.MeshBasicMaterial({
          map: texture,
          transparent: layer.plane === "front" || layer.id !== "00-sky",
          opacity: layer.opacity ?? 1,
          depthTest: false,
          depthWrite: false,
          toneMapped: false,
        });
        const mesh = new THREE.Mesh(geometry, material);
        mesh.position.z = layer.depth;
        mesh.renderOrder = index;
        (layer.plane === "back" ? backScene : frontScene).add(mesh);
        const record = { layer, mesh, textureAspect };
        records.push(record);
        return record;
      }));
      return loaded;
    };

    const fitPlanes = () => {
      const width = Math.max(1, stage.clientWidth);
      const height = Math.max(1, stage.clientHeight);
      const viewportAspect = width / height;
      for (const renderer of [backRenderer, frontRenderer]) renderer.setSize(width, height, false);
      for (const cameraInstance of [backCamera, frontCamera]) {
        cameraInstance.aspect = viewportAspect;
        cameraInstance.updateProjectionMatrix();
      }
      const initial = sampleCamera(camera, 0);
      const verticalFov = THREE.MathUtils.degToRad(initial.fov);
      for (const record of records) {
        const distance = Math.max(0.1, initial.z - record.layer.depth);
        const visibleHeight = 2 * Math.tan(verticalFov / 2) * distance;
        const visibleWidth = visibleHeight * viewportAspect;
        const fit = Math.max(visibleHeight, visibleWidth / record.textureAspect) * 1.035;
        record.mesh.userData.baseScale = fit;
      }
    };

    const resizeObserver = new ResizeObserver(fitPlanes);
    resizeObserver.observe(stage);
    const intersectionObserver = new IntersectionObserver(
      ([entry]) => { intersectionRef.current = Boolean(entry?.isIntersecting); },
      { rootMargin: "25% 0px" },
    );
    intersectionObserver.observe(stage);

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previousTime) / 1000));
      previousTime = time;
      if (intersectionRef.current && document.visibilityState === "visible") {
        smoothed = damp(smoothed, sceneProgress.get(), smoothing, delta);
        visibleProgress.set(smoothed);
        onProgressChange?.(smoothed);
        pointerRef.current.x = damp(pointerRef.current.x, targetPointerRef.current.x, 8, delta);
        pointerRef.current.y = damp(pointerRef.current.y, targetPointerRef.current.y, 8, delta);

        const sampled = sampleCamera(camera, smoothed);
        const pointerX = mobile ? 0 : pointerRef.current.x * pointerStrength;
        const pointerY = mobile ? 0 : pointerRef.current.y * pointerStrength;
        for (const cameraInstance of [backCamera, frontCamera]) {
          cameraInstance.position.set(sampled.x + pointerX, sampled.y - pointerY, sampled.z);
          cameraInstance.fov = sampled.fov;
          cameraInstance.lookAt(sampled.lookX + pointerX * 0.18, sampled.lookY - pointerY * 0.12, 0);
          cameraInstance.updateProjectionMatrix();
        }
        for (const record of records) {
          const sampledLayer = sampleLayer(record.layer, smoothed);
          const baseScale = resolveNumber(record.mesh.userData.baseScale as number | undefined, 1);
          record.mesh.position.set(sampledLayer.x, sampledLayer.y, record.layer.depth + sampledLayer.z);
          record.mesh.scale.setScalar(baseScale * sampledLayer.scale);
          record.mesh.material.opacity = sampledLayer.opacity;
        }
        backRenderer.render(backScene, backCamera);
        frontRenderer.render(frontScene, frontCamera);
      }
      frame = requestAnimationFrame(render);
    };

    load()
      .then(() => {
        if (disposed) return;
        fitPlanes();
        backRenderer.render(backScene, backCamera);
        frontRenderer.render(frontScene, frontCamera);
        setReady(true);
        frame = requestAnimationFrame(render);
      })
      .catch(abort);

    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
      backCanvas.removeEventListener("webglcontextlost", abort);
      frontCanvas.removeEventListener("webglcontextlost", abort);
      for (const record of records) {
        record.mesh.geometry.dispose();
        record.mesh.material.map?.dispose();
        record.mesh.material.dispose();
      }
      backRenderer.dispose();
      frontRenderer.dispose();
    };
  }, [
    camera,
    layerSignature,
    layers,
    maxDpr,
    mobile,
    onProgressChange,
    pointerStrength,
    prefersReducedMotion,
    sceneProgress,
    smoothing,
    visibleProgress,
  ]);

  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => {
    if (!mobile && event.pointerType !== "touch") {
      const rect = event.currentTarget.getBoundingClientRect();
      targetPointerRef.current.x = (event.clientX - rect.left) / Math.max(1, rect.width) - 0.5;
      targetPointerRef.current.y = (event.clientY - rect.top) / Math.max(1, rect.height) - 0.5;
    }
    onPointerMove?.(event);
  };
  const handlePointerLeave = (event: React.PointerEvent<HTMLElement>) => {
    targetPointerRef.current = { x: 0, y: 0 };
    onPointerLeave?.(event);
  };

  if (prefersReducedMotion && reducedMotionFallback) {
    return (
      <section ref={rootRef} aria-label={label} data-depth-camera-scene data-reduced-motion className={className} style={style} {...props}>
        {reducedMotionFallback}
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-depth-camera-scene
      data-ready={ready || undefined}
      data-fallback={failed || undefined}
      className={cn("relative isolate", className)}
      style={{ minHeight: `${Math.max(1, scrollScreens) * 100}svh`, ...style }}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerLeave}
      {...props}
    >
      <div ref={stageRef} className={cn("sticky top-0 h-svh overflow-hidden bg-black", stageClassName)}>
        <picture className={cn("absolute inset-0 z-0 block transition-opacity duration-700", ready && !failed ? "opacity-0" : "opacity-100")}>
          {mobilePoster ? <source media={`(max-width: ${mobileBreakpoint - 0.02}px)`} srcSet={mobilePoster} /> : null}
          <img alt="" src={poster} className="size-full object-cover" decoding="async" fetchPriority="high" />
        </picture>
        <canvas ref={backCanvasRef} aria-hidden className={cn("absolute inset-0 z-10 size-full transition-opacity duration-500", ready && !failed ? "opacity-100" : "opacity-0")} />
        <div className="pointer-events-none absolute inset-0 z-20">
          {renderOverlay(backOverlay, visibleProgress)}
        </div>
        <canvas ref={frontCanvasRef} aria-hidden className={cn("pointer-events-none absolute inset-0 z-30 size-full transition-opacity duration-500", ready && !failed ? "opacity-100" : "opacity-0")} />
        <div className="pointer-events-none absolute inset-0 z-40">
          {renderOverlay(frontOverlay, visibleProgress)}
        </div>
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import { motion, type MotionValue, useTransform } from "motion/react";

import { cn } from "@/lib/utils";

export type HorizontalTrackMetrics = {
  distance: number;
  trackWidth: number;
  viewportHeight: number;
  viewportWidth: number;
};

export type HorizontalTrackProps = Omit<React.ComponentProps<"div">, "children"> & {
  children: React.ReactNode;
  itemClassName?: string | ((index: number) => string | undefined);
  label: string;
  onMetricsChange?: (metrics: HorizontalTrackMetrics) => void;
  progress: MotionValue<number>;
  progressClassName?: string;
  progressIndicatorClassName?: string;
  showProgress?: boolean;
  trackClassName?: string;
};

function sameMetrics(left: HorizontalTrackMetrics, right: HorizontalTrackMetrics) {
  return left.distance === right.distance
    && left.trackWidth === right.trackWidth
    && left.viewportHeight === right.viewportHeight
    && left.viewportWidth === right.viewportWidth;
}

/**
 * A measured horizontal track controlled by an external normalized progress.
 * It owns no sticky section or scroll listener, so it can live inside another
 * timeline, a 2.5D stage, a carousel controller, or a standalone composition.
 */
export function HorizontalTrack({
  children,
  className,
  itemClassName,
  label,
  onMetricsChange,
  progress,
  progressClassName,
  progressIndicatorClassName,
  showProgress = true,
  style,
  trackClassName,
  ...props
}: HorizontalTrackProps) {
  const viewportRef = React.useRef<HTMLDivElement>(null);
  const trackRef = React.useRef<HTMLDivElement>(null);
  const metricsRef = React.useRef<HorizontalTrackMetrics>({
    distance: 0,
    trackWidth: 0,
    viewportHeight: 0,
    viewportWidth: 0,
  });
  const items = React.Children.toArray(children);
  const [distance, setDistance] = React.useState(0);
  const x = useTransform(progress, [0, 1], [0, -distance], { clamp: true });
  const progressScale = useTransform(progress, (value) => Math.max(0, Math.min(1, value)));

  React.useEffect(() => {
    const viewport = viewportRef.current;
    const track = trackRef.current;
    if (!viewport || !track) return;

    const measure = () => {
      const next: HorizontalTrackMetrics = {
        distance: Math.max(0, track.scrollWidth - viewport.clientWidth),
        trackWidth: track.scrollWidth,
        viewportHeight: viewport.clientHeight,
        viewportWidth: viewport.clientWidth,
      };
      if (sameMetrics(metricsRef.current, next)) return;
      metricsRef.current = next;
      setDistance(next.distance);
      onMetricsChange?.(next);
    };

    const observer = new ResizeObserver(measure);
    observer.observe(viewport);
    observer.observe(track);
    measure();
    return () => observer.disconnect();
  }, [items.length, onMetricsChange]);

  return (
    <div
      ref={viewportRef}
      data-horizontal-track-viewport
      className={cn("relative flex h-full w-full items-center overflow-hidden", className)}
      style={style}
      {...props}
    >
      <motion.div
        ref={trackRef}
        role="list"
        aria-label={label}
        data-horizontal-track
        className={cn(
          "flex w-max items-stretch gap-[clamp(1rem,2.5vw,2.5rem)] px-[max(1.25rem,5vw)] will-change-transform",
          trackClassName,
        )}
        style={{ x }}
      >
        {items.map((child, index) => {
          const key = React.isValidElement(child) && child.key != null ? child.key : index;
          const resolvedItemClassName = typeof itemClassName === "function"
            ? itemClassName(index)
            : itemClassName;

          return (
            <div
              key={key}
              role="listitem"
              aria-label={`${index + 1} din ${items.length}`}
              data-horizontal-track-item={index}
              className={cn("w-[min(82vw,62rem)] shrink-0", resolvedItemClassName)}
            >
              {child}
            </div>
          );
        })}
      </motion.div>

      {showProgress ? (
        <div
          aria-hidden
          className={cn(
            "absolute inset-x-[max(1.25rem,5vw)] bottom-6 h-px origin-left bg-current/20",
            progressClassName,
          )}
        >
          <motion.div
            className={cn("h-full origin-left bg-current", progressIndicatorClassName)}
            style={{ scaleX: progressScale }}
          />
        </div>
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = [...frames].sort((left, right) => left.at - right.at);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(() => {
        const rect = element.getBoundingClientRect();
        const travel = Math.max(1, element.offsetHeight - window.innerHeight);
        progress.set(Math.max(0, Math.min(1, -rect.top / travel)));
      });
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    update();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [progress, target]);

  return progress;
}

# HorizontalTrack

Motor orizontal măsurat, controlat exclusiv printr-un `MotionValue<number>` extern. Componenta nu creează o secțiune sticky, nu citește scroll-ul global și nu impune un timeline. Poate fi montată într-o scenă 2.5D, într-un controller de carousel sau într-un alt recipe.

## Instalare

```bash
npx shadcn@latest add ./public/r/horizontal-track.json
```

## Exemplu controlat

```tsx
import { useTransform } from "motion/react"

import { HorizontalTrack } from "@/components/experience/horizontal-track"

const catalogProgress = useTransform(sceneProgress, [0.75, 0.96], [0, 1], {
  clamp: true,
})

<HorizontalTrack
  label="Catalog"
  progress={catalogProgress}
  itemClassName={(index) => index === 1 ? "w-[56vw]" : "w-[34vw]"}
  trackClassName="gap-4 px-[8vw]"
>
  {items.map((item) => <CatalogCard key={item.id} item={item} />)}
</HorizontalTrack>
```

`progress` este normalizat la `0…1`. Componenta măsoară `track.scrollWidth - viewport.clientWidth`, observă track-ul și viewport-ul cu `ResizeObserver` și recalculează automat după resize, font loading sau schimbarea dimensiunilor conținutului.

## Contract

- `HorizontalTrack` este o infrastructură controlată, nu o mecanică signature pe care Studio o propune singură clientului;
- parent-ul decide sursa progresului, sticky behavior-ul, timeline-ul și fallback-ul reduced-motion;
- `itemClassName` acceptă o clasă comună sau o funcție per index, deci item-urile pot avea lățimi diferite;
- `trackClassName` personalizează gap-ul, padding-ul și alinierea;
- `onMetricsChange` expune distanța, dimensiunea track-ului și viewport-ul pentru controllere externe;
- conținutul rămâne React semantic, iar ordinea DOM nu se schimbă.

Pentru varianta vertical-scroll completă folosește `HorizontalStoryRail`. Pentru catalogul final al unei scene cinematice, compune `HorizontalTrack` cu un controller de index/drag și animă intrarea întregului catalog prin timeline-ul scenei.

## QA

- testează `progress` la `0`, `0.5` și `1`;
- modifică lățimea viewport-ului după montare;
- verifică item-uri cu lățimi diferite și conținut încărcat lent;
- verifică faptul că primul și ultimul item se așază complet;
- parent-ul trebuie să ofere fallback normal pentru touch și `prefers-reduced-motion`;
- nu transforma acest building block într-un carousel fără controale, drag/swipe și tastatură.
